import React, { useState, useEffect } from 'react';
import axios from 'axios';
import API_BASE from '../config';
import { initCaptivateServiceHandler, sendVariablesToCaptivate } from '../utils/captivateServiceHandler';

function ProducerDashboard() {
  const [player1Email, setPlayer1Email] = useState('');
  const [player2Email, setPlayer2Email] = useState('');
  const [player1Decks, setPlayer1Decks] = useState([]);
  const [player2Decks, setPlayer2Decks] = useState([]);
  const [selectedDeck1, setSelectedDeck1] = useState(null);
  const [selectedDeck2, setSelectedDeck2] = useState(null);
  const [gameId, setGameId] = useState('');
  const [loadGameId, setLoadGameId] = useState('');
  const [gameData, setGameData] = useState(null);

  useEffect(() => {
    initCaptivateServiceHandler();
  }, []);

  const fetchDecks = async (email, setDecks) => {
    try {
      const res = await axios.get(`${API_BASE}/api/decks?email=${email}`);
      setDecks(res.data);
    } catch (err) {
      console.error('Error fetching decks:', err);
    }
  };

  const handleStartGame = async () => {
    try {
      const res = await axios.post(`${API_BASE}/api/games`, {
        player1Email,
        player2Email,
        deck1Id: selectedDeck1,
        deck2Id: selectedDeck2,
      });
      setGameId(res.data._id);
      fetchGameStateForCaptivate(res.data._id);
    } catch (err) {
      console.error('Error starting game:', err);
    }
  };

  const handleStartRound = async () => {
    if (!gameId) return;
    try {
      await axios.post(`${API_BASE}/api/games/${gameId}/start-round`);
      fetchGameStateForCaptivate(gameId);
    } catch (err) {
      console.error('Error starting round:', err);
    }
  };

  const fetchGameStateForCaptivate = async (id) => {
    try {
      const res = await axios.get(`${API_BASE}/api/games/${id}`);
      setGameData(res.data);

      // Map to flat variable structure for Captivate
      const variables = {
        player1_name: res.data.player1?.name || res.data.player1?.email || '',
        player1_handle: res.data.player1?.handle || res.data.player1?.email || '',
        player1_avatarUrl: res.data.player1?.avatarUrl || '',
        player1_aura: res.data.player1?.score?.aura || 0,
        player1_skill: res.data.player1?.score?.skill || 0,
        player1_stamina: res.data.player1?.score?.stamina || 0,
        player2_name: res.data.player2?.name || res.data.player2?.email || '',
        player2_handle: res.data.player2?.handle || res.data.player2?.email || '',
        player2_avatarUrl: res.data.player2?.avatarUrl || '',
        player2_aura: res.data.player2?.score?.aura || 0,
        player2_skill: res.data.player2?.score?.skill || 0,
        player2_stamina: res.data.player2?.score?.stamina || 0,
        // Add more variables as needed for your Captivate setup
      };
      sendVariablesToCaptivate(variables);
    } catch (err) {
      console.error('Error fetching game state for Captivate:', err);
    }
  };

  const handleLoadGame = () => {
    if (loadGameId) {
      setGameId(loadGameId);
      fetchGameStateForCaptivate(loadGameId);
    }
  };

  return (
    <div>
      <h2>Game Setup</h2>
      <div>
        <h3>Player 1</h3>
        <input
          type="email"
          placeholder="Enter Player 1 Email"
          value={player1Email}
          onChange={e => setPlayer1Email(e.target.value)}
        />
        <button onClick={() => fetchDecks(player1Email, setPlayer1Decks)}>Load Decks</button>
        <select onChange={e => setSelectedDeck1(e.target.value)} value={selectedDeck1 || ''}>
          <option value="">Select Deck</option>
          {player1Decks.map(deck => (
            <option key={deck._id} value={deck._id}>{deck.name}</option>
          ))}
        </select>
      </div>
      <div>
        <h3>Player 2</h3>
        <input
          type="email"
          placeholder="Enter Player 2 Email"
          value={player2Email}
          onChange={e => setPlayer2Email(e.target.value)}
        />
        <button onClick={() => fetchDecks(player2Email, setPlayer2Decks)}>Load Decks</button>
        <select onChange={e => setSelectedDeck2(e.target.value)} value={selectedDeck2 || ''}>
          <option value="">Select Deck</option>
          {player2Decks.map(deck => (
            <option key={deck._id} value={deck._id}>{deck.name}</option>
          ))}
        </select>
      </div>
      <button onClick={handleStartGame}>Start Game</button>
      <button onClick={handleStartRound} disabled={!gameId}>Start Round</button>
      <div>
        <h3>Load Existing Game</h3>
        <input
          type="text"
          placeholder="Game ID"
          value={loadGameId}
          onChange={e => setLoadGameId(e.target.value)}
        />
        <button onClick={handleLoadGame}>Load Game</button>
      </div>
      <div>
        <button onClick={() => sendVariablesToCaptivate(gameData || {})}>
          Send Data to Captivate
        </button>
      </div>
    </div>
  );
}

export default ProducerDashboard;
